def guard(features: dict, prediction: str) -> str:
    vwap_dev = features.get('vwap_deviation', 0)
    momentum = features.get('momentum_score', 0)
    stoch_k = features.get('stoch_k', 50)

    # Primary check: momentum and VWAP position disagreement with prediction
    if prediction == "long":
        if momentum < 0 and vwap_dev < -0.01:
            return "skip"
        if stoch_k > 85:
            return "skip"
    elif prediction == "short":
        if momentum > 0 and vwap_dev > 0.01:
            return "skip"
        if stoch_k < 15:
            return "skip"

    return prediction
